I've been playing around with an extension to python-chess that I at least find very useful. Thought I'd share it. I'm just going to paste a code dump here rather than make a pull request, because if Niklas (or others) have any interest in it, I'd expect they could want the api or implementation to be different. But this is what works for me.

```
from chess import Board,BLACK,WHITE,Move
import chess.pgn as Pgn
import re

def list_startswith(long, short, *, proper=False):
  if proper:
    if len(short) >= len(long):
      return False
  else:
    if len(short) > len(long):
      return False
  for l, s in zip(long, short):
    if l != s:
      return False
  return True

def board_rewind(b, n=None):
  """Do multiple pops; contrast b.clear_stack(), which erases move/state history without altering the state itself"""
  if n is None:
    if not b.stack: return
    state = b.stack[0]
    b.stack.clear()
    b.move_stack.clear()
  else:
    assert n >= 0
    if not n: return
    for _ in range(n):
      state = b.stack.pop()
      b.move_stack.pop()
  b.pawns = state.pawns
  b.knights = state.knights
  b.bishops = state.bishops
  b.rooks = state.rooks
  b.queens = state.queens
  b.kings = state.kings
  b.occupied_co[WHITE] = state.occupied_w
  b.occupied_co[BLACK] = state.occupied_b
  b.occupied = state.occupied
  b.promoted = state.promoted
  b.turn = state.turn
  b.castling_rights = state.castling_rights
  b.ep_square = state.ep_square
  b.halfmove_clock = state.halfmove_clock
  b.fullmove_number = state.fullmove_number

def late_board(board):
  """True if board lacks a full history."""
  if not board.stack:
    return board.fen() != "rnbqkbnr/pppppppp/8/8/8/8/PPPPPPPP/RNBQKBNR w KQkq - 0 1"
  else:
    return len(board.stack) != 2*board.fullmove_number - (2 if board.turn else 1)

def to_var(moves, board=Board(chess960=True)):
  """
  Enhanced version of Board.variation_san.

  Given a sequence of moves, return a string representing the sequence
  in standard algebraic notation (e.g. "1.e4 e5 2.Nf3 Nc6" or "37...Bg6 38.fxg6")
  (notice no spaces after the turn numbers! blech),
  followed by a tuple of the individual sans (e.g. ("e4", "e5", ...)).

  ValueError will be thrown if any moves in the sequence are illegal.

  Board will not be modified as a result of calling this.
  """
  b = board.copy(stack=False)
  pretty = []
  sans = []
  for move in moves:
    if not b.is_legal(move):
      raise ValueError("illegal move {0} in position {1}".format(move, b.fen()))
    san = b.san(move)
    if b.turn == WHITE:
      pretty.append("{0}.{1}".format(b.fullmove_number, san))
    elif not pretty:
      pretty.append("{0}...{1}".format(b.fullmove_number, san))
    else:
      pretty.append(san)
    sans.append(san)
    b.push(move)
  return " ".join(pretty), tuple(sans)

class Var(str):
  """Constructors
  ------------
  Var("1.e4 e5", verify=False)
  Var.partial("1...e5", verify=board)  # without a base board you can extract .sans, .turn, .last_ply; but not .move() nor .board()
  Var.from_board(board)"""

  _move = '(?:--|O-O|O-O-O|[BRQNK][a-h]?x?[a-h][1-8]|[BRQNK][a-h]?[1-8]x?[a-h][1-8]|(?:[a-h][1-8])?[a-h][1-8](?:[=][BNRQ])?|[a-h][1-8]?x[a-h][1-8](?:[=][BNRQ])?)[+#]?'
  _annot = '(?:![!?]?|[?][!?]?|)'
  _turn_pat = re.compile(r'(\s*([0-9]+)(?:[.]\s*({move}){annot}(?:\s+({move}){annot})?|(?:[.][.][.]|…)\s*({move}){annot}))(?=\s|[,.;:]|\Z)'.format(move=_move, annot=_annot))
  _unparsed_pat = re.compile(r'\s*(?:[0-9]+(?:[.]|[.][.][.]|…)\s*)?{move}\b'.format(move=_move))
  _move_pat = re.compile('({move}){annot}'.format(move=_move, annot=_annot))

  _moves = None
  _sans = None
  _last_ply = None
  _turn = None
  _board = None
  first_ply = 1

  def __new__(cls, string, *, verify=None):
    if isinstance(string, cls):
      return string
    elif verify is None:
      return super(Var, cls).__new__(cls, string)
    else:
      string, sans, first_ply, suffix = cls._parse(string, partial=False)
      if suffix:
        raise ValueError("Suffix: " + suffix)
      assert first_ply == 1
      self = super(Var, cls).__new__(cls, string)
      self._sans = sans
      return self

  def __init__(self, string, *, verify=None):
    """If verify=False, string is parsed but moves aren't verified. If verify=None, neither is done."""
    if self is string or not verify:
      return
    b = Board()
    for san in self._sans:
      b.push_san(san)
    self._moves = tuple(b.move_stack)

  @classmethod
  def _join(cls, n, sans):
    if not sans:
      v = cls('')
      v.first_ply = n
      return v
    res = []
    space = ''
    n0 = n
    n += 1
    if n % 2:
      res.append(str(n//2))
      res.append('...')
    for san in sans:
      res.append(space)
      space = ' '
      if n % 2 == 0:
        res.append(str(n//2))
        res.append('.')
      res.append(san)
      n += 1
    v = cls(''.join(res))
    v.first_ply = n0
    return v

  @staticmethod
  def _parse(string, *, partial=False):
    lines = Var._turn_pat.sub(r'\n\2\t\3\t\4\t\5\t\1\t', string).split('\n')
    lines = [s.split('\t') for s in lines]
    line0 =lines.pop(0)[0].lstrip()
    if line0:
      raise ValueError('Unparseable: ' + string)
      # raise ValueError('Unparseable: ' + line0 + ''.join(t[4] for t in lines))
    elif not lines:
      assert not string.strip()
      return string, (), 1, ""
    res = []
    n0 = n = int(lines[0][0])
    suffix = ''
    while lines:
      s = lines.pop(0)
      if s[3] != '':
        if n > n0:
          raise ValueError('Missing move: ' + s[4])
        assert s[1] == '' and s[2] == ''
        s[2] = s[3]
      if n != int(s[0]) or n < 1:
        raise ValueError('Bad turn number: ' + s[4])
      if not s[2] and lines:
        raise ValueError('Short turn: ' + s[4])
      n += 1
      res.append((s[1], s[2]))
      if s[5]:
        suffix = s[5] + ''.join(t[4] for t in lines)
        break
    if Var._unparsed_pat.match(suffix):
      raise ValueError('Unparsed: ' + suffix)
    assert string.endswith(suffix)
    if suffix:
      string = string[:-len(suffix)]
    if not res:
      assert n0 == 1
      sans = ()
      first_ply = 1
    else:
      sans = []
      if n0 == 1 and res[0][0]:
        first_ply = 1
      elif not partial:
        raise ValueError('Partial variation: ' + string)
      else:
        first_ply = 2*n0 - 1
        if res[0][0] == '':
          first_ply += 1
          sans.append(res.pop(0)[1])
      for r in res:
        sans.extend(r)
      if res and res[-1][1] == '':
        sans.pop()
      sans = tuple(sans)
    return string, sans, first_ply, suffix.strip()

  @classmethod
  def partial(cls, string, *, verify=None):
    string, sans, first_ply, suffix = cls._parse(string, partial=True)
    if suffix:
      raise ValueError('Suffix: ' + suffix)
    self = cls(string)
    self._sans = sans
    self.first_ply = first_ply
    if verify is not None:
      if isinstance(verify, Var):
        verify = verify.board()
      elif not isinstance(verify, Board):
        raise TypeError("Should be partial(..., verify=Board)")
      verify_ply = 2*verify.fullmove_number - (1 if verify.turn else 0)
      if sans == ():
        assert first_ply == 1
        self.first_ply = verify_ply
      elif first_ply != verify_ply:
        raise ValueError("Mismatched turns")
      self._board = board = verify.copy(stack=False)
      for san in sans:
        board.push_san(san)
      self._moves = tuple(board.move_stack)
      board_rewind(board)
    return self

  @classmethod
  def from_board(cls, b):
    if late_board(b):
      b0 = b.copy()
      board_rewind(b0)
      string, sans = to_var(b.move_stack, b0)
      first_ply = 2*b0.fullmove_number - (1 if b0.turn else 0)
    else:
      string, sans = to_var(b.move_stack)
      first_ply = 1
    v = cls(string)
    v._moves = tuple(b.move_stack)
    v._sans = sans
    v.first_ply = first_ply
    v._last_ply = len(b.move_stack) + first_ply - 1
    v._turn = b.turn
    return v

  def board(self):
    if self._board is None:
      b = Board()
    else:
      b = self._board.copy(stack=False) # stack will normally be empty anyway
    if not self:
      return b
    sans = self.sans # may force parsing
    # if self.first_ply != 1: raise ValueError('Partial variation: ' + self)
    if self._moves is None:
      for san in sans:
        b.push_san(san)
      self._moves = tuple(b.move_stack)
    else:
      for m in self._moves:
        b.push(m)
    return b
    # from io import StringIO
    # return Pgn.read_game(StringIO(self)).end().board()

  def moves(self):
    if self._moves is None:
      assert self.first_ply == 1
      b = Board()
      for san in self.sans:
        b.push_san(san)
      self._moves = tuple(b.move_stack)
    return self._moves

  @property
  def sans(self):
    if self._sans is None:
      _, sans, _, suffix = self._parse(self, partial=False)
      if suffix:
        raise ValueError('Suffix: ' + suffix)
      self._sans = sans
    return self._sans

  @property
  def last_ply(self):
    if self._last_ply is None:
      self._last_ply = len(self.sans) + self.first_ply - 1
    return self._last_ply

  @property
  def turn(self):
    if self._turn is None:
      self._turn = self.last_ply % 2 == 0
    return self._turn

  def append(self, san):
    m = Var._move_pat.fullmatch(san)
    if not m:
      raise ValueError(san)
    more_sans = self.sans + (m.group(0),)
    v = Var._join(self.first_ply, more_sans)
    # v._moves = None
    v._sans = more_sans
    v._last_ply = self.last_ply + 1
    v._turn = not self.turn
    v._board = self._board
    return v

  def __eq__(self, other):
    if self is other:
      return True
    elif isinstance(other, Board):
      return self.board() == other
    elif not isinstance(other, str):
      return NotImplemented
    if not isinstance(other, Var):
      other = Var(other)
    if self.last_ply != other.last_ply:
      return False
    elif other.first_ply < self.first_ply:
      skip = self.first_ply - other.first_ply
      assert len(other.moves()) >= skip
      return self._board and self._board == other.slice(skip).board() and other.moves()[skip:] == self.moves()
    elif other.first_ply == self.first_ply:
      return self._board == other._board and other.moves() == self.moves()
    elif other.first_ply <= self.last_ply:
      skip = other.first_ply - self.first_ply
      assert len(self.moves()) >= skip
      return other._board and self.slice(skip).board() == other._board and other.moves() == self.moves()[skip:]
    elif other.first_ply == self.last_ply + 1:
      assert not other.moves()
      return other._board and self.board() == other._board
    else:
      # no overlap
      return False

  def __ne__(self, other):
    return not self.__eq__(other)

  def __le__(self, other):
    if not isinstance(other, str):
      return NotImplemented
    if not isinstance(other, Var):
      other = Var(other)
    if self.last_ply > other.last_ply:
      return False
    elif other.first_ply < self.first_ply:
      skip = self.first_ply - other.first_ply
      assert len(other.moves()) >= skip
      return self._board and self._board == other.slice(skip).board() and list_startswith(other.moves()[skip:], self.moves())
    elif other.first_ply == self.first_ply:
      return self._board == other._board and list_startswith(other.moves(), self.moves())
    elif other.first_ply <= self.last_ply:
      skip = other.first_ply - self.first_ply
      assert len(self.moves()) >= skip
      return other._board and self.slice(skip).board() == other._board and list_startswith(other.moves(), self.moves()[skip:])
    elif other.first_ply == self.last_ply + 1:
      return other._board and self.board() == other._board
    else:
      # no overlap
      return False

  def __lt__(self, other):
    if not isinstance(other, str):
      return NotImplemented
    if not isinstance(other, Var):
      other = Var(other)
    if self.last_ply >= other.last_ply:
      return False
    elif other.first_ply < self.first_ply:
      skip = self.first_ply - other.first_ply
      assert len(other.moves()) >= skip
      return self._board and self._board == other.slice(skip).board() and list_startswith(other.moves()[skip:], self.moves(), proper=True)
    elif other.first_ply == self.first_ply:
      return self._board == other._board and list_startswith(other.moves(), self.moves(), proper=True)
    elif other.first_ply <= self.last_ply:
      skip = other.first_ply - self.first_ply
      assert len(self.moves()) >= skip
      return other._board and self.slice(skip).board() == other._board and list_startswith(other.moves(), self.moves()[skip:], proper=True)
    elif other.first_ply == self.last_ply + 1:
      return other._board and self.board() == other._board
    else:
      # no overlap
      return False

  def __ge__(self, other):
    if not isinstance(other, str):
      return NotImplemented
    if not isinstance(other, Var):
      other = Var(other)
    return other.__le__(self)

  def __gt__(self, other):
    if not isinstance(other, str):
      return NotImplemented
    if not isinstance(other, Var):
      other = Var(other)
    return other.__lt__(self)

  def extend(self, sans):
    if isinstance(sans, Var):
      if self.last_ply + 1 != sans.first_ply:
        raise ValueError("Mismatched turns")
      elif sans._board and sans._board != self.board():
        raise ValueError("Mismatched boards")
      ms = sans.sans
    else:
      if isinstance(sans, str):
        sans = sans.split()
      ms = []
      for san in sans:
        m = Var._move_pat.fullmatch(san)
        if not m:
          raise ValueError(san)
        ms.append(m.group(0))
    more_sans = self.sans + tuple(ms)
    v = Var._join(self.first_ply, more_sans)
    if isinstance(sans, Var) and self._moves is not None and sans._moves is not None:
      v._moves = self._moves + sans._moves
    v._sans = more_sans
    v._last_ply = self.last_ply + len(ms)
    v._turn = not self.turn if len(ms) % 2 else self.turn
    v._board = self._board
    return v

  def slice(self, stop):
    """slice(...,N>=0) gives first N plies; slice(...,-N) drops N plies from the end"""
    if False and stop == 0:
      return self
    else:
      less_sans = self.sans[:stop]
      v = Var._join(self.first_ply, less_sans)
      if self._moves is not None:
        v._moves = self._moves[:stop]
      v._sans = less_sans
      # v._last_ply = None
      # v._turn = None
      v._board = self._board
      return v

  def pop(self):
    sans = self.sans # may force parsing
    if not sans:
      raise ValueError("pop from empty Var")
    less_sans, san = sans[:-1], sans[-1]
    v = Var._join(self.first_ply, less_sans)
    if self._moves:
      v._moves = self._moves[:-1]
    v._sans = less_sans
    v._last_ply = self.last_ply - 1
    v._turn = not self.turn
    v._board = self._board
    return v, san
```

